const DB = 'MangaVizCache', VER = 1, STORE = 'cache';
// #region debug-point B:indexeddb-cache
const DEBUG_SERVER_URL = 'http://127.0.0.1:7778/event';
const DEBUG_SESSION_ID = 'live-request-failure';
const reportDebug = (hypothesisId, msg, data) => { void fetch(DEBUG_SERVER_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ sessionId: DEBUG_SESSION_ID, runId: 'pre-fix', hypothesisId, location: 'src/cache/indexedDbCache.ts', msg: `[DEBUG] ${msg}`, data, ts: Date.now() }) }).catch(() => {}); };
// #endregion
function open(): Promise<IDBDatabase> { return new Promise((res,rej) => { const r = indexedDB.open(DB,VER); r.onupgradeneeded = () => { if (!r.result.objectStoreNames.contains(STORE)) r.result.createObjectStore(STORE, {keyPath:'k'}); }; r.onsuccess = () => res(r.result); r.onerror = () => rej(r.error); }); }
export async function cacheGet<T>(key: string, ttl = 3600000): Promise<T|null> { try { const db = await open(); return new Promise(r => { const req = db.transaction(STORE,'readonly').objectStore(STORE).get(key); req.onsuccess = () => { const e = req.result; const expired = !e || Date.now()-e.ts > e.ttl; reportDebug('B', 'indexeddb cache get resolved', { db: DB, store: STORE, key, requestedTtl: ttl, storedTtl: e?.ttl ?? null, hit: !!e, expired }); if (!e || expired) { if (e) db.transaction(STORE,'readwrite').objectStore(STORE).delete(key); r(null); } else r(e.data as T); }; req.onerror = () => { reportDebug('B', 'indexeddb cache get errored', { db: DB, store: STORE, key }); r(null); }; }); } catch (error) { reportDebug('B', 'indexeddb cache get threw', { db: DB, store: STORE, key, error: error instanceof Error ? error.message : 'unknown' }); return null; } }
export async function cacheSet(key: string, data: unknown, ttl = 3600000): Promise<void> { try { const db = await open(); await new Promise<void>((res,rej) => { const t = db.transaction(STORE,'readwrite'); t.objectStore(STORE).put({k:key,data,ts:Date.now(),ttl}); t.oncomplete = () => { reportDebug('B', 'indexeddb cache set completed', { db: DB, store: STORE, key, ttl }); res(); }; t.onerror = () => { reportDebug('B', 'indexeddb cache set errored', { db: DB, store: STORE, key, ttl, error: t.error?.message || 'unknown' }); rej(t.error); }; }); } catch (error) { reportDebug('B', 'indexeddb cache set threw', { db: DB, store: STORE, key, ttl, error: error instanceof Error ? error.message : 'unknown' }); } }
